import{j as e}from"./ui-vendor-CUvJdy9K.js";import{S as r}from"./ServicePageTemplate-Cf7lJlsr.js";import{Z as t}from"./zap-CKfPtl3r.js";import"./react-vendor-CSY-tL5Y.js";import"./index-C03muQI3.js";import"./Footer-BLN0AZOI.js";import"./phone-CNIer0s9.js";import"./AnimatedSection-C8ujN5LE.js";import"./breadcrumb-CJtEwarS.js";import"./index-wnGSTn9f.js";import"./utils-BLSKlp9E.js";import"./sections-CSJ2HaIa.js";import"./accordion-C-rbFL94.js";import"./circle-check-big-DPMznW8r.js";const c=()=>e.jsx(r,{title:"Prestanda-optimering",metaTitle:"Prestanda & Core Web Vitals | LRH Konsult",metaDescription:"Optimera din hemsidas hastighet i Västmanland. Vi fixar Core Web Vitals, bildoptimering och cachning. Snabbare sajt = bättre ranking och fler kunder.",heroSubheading:"Prestanda",heroHeading:"Prestanda-optimering för snabbare affärer",heroDescription:"Sidhastighet är den dolda nyckeln till framgång online. Vi utför djupgående prestandaoptimering för företag i Västerås och Västmanland som vill sänka sina laddtider, klättra i sökresultaten och öka sina konverteringar genom bättre Core Web Vitals.",whyTitle:"Core Web Vitals-optimering i Västmanland",whyText:"Google mäter din framgång genom användarupplevelsen. Vi optimerar din kod, komprimerar dina bilder och konfigurerar smart cachning för att leverera en blixtsnabb upplevelse. Varje millisekund räknas – både för dina kunder och för din ranking.",icon:t,breadcrumbLabel:"Prestanda-optimering",features:[{title:"Core Web Vitals",description:"Optimering av LCP, INP och CLS för att nå Googles gröna tröskelvärden och maximera din ranking."},{title:"Bildoptimering",description:"Automatisk komprimering, lazy loading och moderna format (WebP/AVIF) för snabbare laddning utan kvalitetsförlust."},{title:"Cachning & CDN",description:"Smart cachning-strategi och CDN-konfiguration för snabb leverans oavsett besökarens geografiska plats."},{title:"Konverteringsoptimering",description:"Snabbare sajt = fler konverteringar. Vi kopplar prestandaförbättringar direkt till mätbara affärsresultat."},{title:"Före & efter-rapport",description:"Detaljerad rapport med mätbara förbättringar i Lighthouse-poäng, laddtider och Core Web Vitals."}],process:[{step:"1",title:"Prestandaanalys",description:"Vi kör Lighthouse, WebPageTest och Chrome DevTools för att identifiera exakt vad som saktar ner din sajt och prioritera åtgärder efter påverkan."},{step:"2",title:"Prioriterad åtgärdsplan",description:"Vi rangordnar alla problem efter förväntad prestandavinst och presenterar en tydlig plan med konkreta förbättringsmål."},{step:"3",title:"Teknisk optimering",description:"Vi implementerar åtgärder: bildkomprimering till AVIF/WebP, koddelning, cachning, CDN-konfiguration, skriptoptimering och rendering-förbättringar."},{step:"4",title:"Verifiering & rapport",description:"Vi mäter resultaten med en detaljerad före/efter-rapport som visar konkreta förbättringar i Lighthouse-poäng och laddtider."}],caseStudies:[{client:"FastTrack AB",metric:"42→98",result:"Lighthouse-poäng efter fullständig prestandaoptimering. Laddtid under 1 sekund."},{client:"Västerås Handel",metric:"-3.4s",result:"Minskad laddtid från 4.2s till 0.8s med bildoptimering och koddelning."},{client:"Sala Bygg",metric:"+25%",result:"Ökning i konverteringsgrad efter att Core Web Vitals nådde gröna tröskelvärden."}],contentSections:[{title:"Kundcase: Från rött till grönt i Lighthouse",paragraphs:["En befintlig webbplats i Västmanland led av höga avhoppsfrekvenser på grund av långsamma laddningstider, särskilt i mobilen. Sajten hade en Lighthouse-poäng på 45 av 100 och laddningstider på över fyra sekunder. Bilderna var okomprimerade, JavaScript-bundlarna onödigt stora och servern saknade korrekt cachning.","Vi genomförde en total prestandaoptimering i flera steg. Först konverterade vi alla bilder till moderna format (AVIF med WebP-fallback) och implementerade responsiva bildstorlekar med lazy loading. Därefter delade vi upp JavaScript-bundlarna med dynamisk import och tree-shaking för att minimera mängden kod som laddades vid sidvisning.","Slutligen konfigurerade vi smart server-side cachning, optimerade CSS-leveransen genom att inlina kritisk CSS och konfigurerade ett CDN för global leverans. Sidan gick från ett rött betyg (45/100) till grönt (98/100) på Google PageSpeed Insights. Avhoppsfrekvensen sjönk med 40 % och konverteringsgraden ökade med 25 %."]},{title:"Varför hastighet avgör din ranking",paragraphs:["Google använder Core Web Vitals – LCP, INP och CLS – som direkta rankingfaktorer. Det innebär att en långsam sida inte bara ger dålig användarupplevelse utan också aktivt straffas i sökresultaten. Studier visar att 53 % av mobilanvändare lämnar en sida som tar mer än tre sekunder att ladda.","LCP (Largest Contentful Paint) mäter hur snabbt det största synliga innehållet renderas. INP (Interaction to Next Paint) mäter responsiviteten – hur snabbt sidan reagerar på klick. CLS (Cumulative Layout Shift) mäter visuell stabilitet – att element inte hoppar runt när sidan laddar. Alla tre måste vara gröna för optimal ranking.","Behöver du bygga om hela sidan för att få den snabb? Inte alltid. Ofta kan vi göra stora förbättringar genom att optimera befintlig kod, komprimera tunga bilder, se över hur resurser laddas och implementera rätt cachning-strategi. Vi börjar alltid med en analys för att identifiera var de största vinsterna finns."]}],faqTitle:"Vanliga frågor om sidhastighet",faq:[{question:"Hur snabb måste en hemsida vara?",answer:"Under 2026 bör en sida ladda på under 1.5 sekunder för att inte tappa besökare och ranking. Google rekommenderar LCP under 2.5 sekunder som minimum."},{question:"Påverkar hastigheten min försäljning?",answer:"Absolut. En snabbare sida leder bevisat till högre konvertering och fler leads. Amazon har visat att varje 100ms extra laddtid kostar 1% i försäljning."},{question:"Kan ni optimera min befintliga sajt?",answer:"Ja, vi utför prestandaanalyser på alla typer av plattformar – WordPress, React, Shopify och mer – och implementerar konkreta förbättringar."},{question:"Vad är Core Web Vitals?",answer:"Det är Googles mätvärden för användarupplevelse: LCP (laddtid), INP (interaktivitet) och CLS (visuell stabilitet). Bra poäng ger direkt bättre ranking i sökresultaten."}],testimonial:{quote:"Vår Lighthouse-poäng gick från 42 till 98. Sajten laddar nu på under en sekund och vi ser direkt fler förfrågningar.",author:"Karin Olsson",role:"Marknadschef, FastTrack AB"},relatedServices:[{label:"SEO-optimering",href:"/tjanster/seo-optimering"},{label:"Webbutveckling",href:"/tjanster/webbutveckling"},{label:"Underhåll & Support",href:"/tjanster/underhall-support"}]});export{c as default};
